import{_ as t,o as d,c as o,a2 as s}from"./chunks/framework.DXCpk3D_.js";const g=JSON.parse('{"title":"Events","description":"","frontmatter":{},"headers":[],"relativePath":"reference/events.md","filePath":"reference/events.md"}'),a={name:"reference/events.md"};function r(n,e,i,c,l,p){return d(),o("div",null,[...e[0]||(e[0]=[s(`<h1 id="events" tabindex="-1">Events <a class="header-anchor" href="#events" aria-label="Permalink to &quot;Events&quot;">​</a></h1><p>OAO emits <strong>system events</strong> for every significant action in the platform. These events are stored in the <code>system_events</code> table and can be used to:</p><ul><li><strong>Trigger workflows</strong> via event-type triggers (match by event name + optional data conditions)</li><li><strong>Audit</strong> platform activity</li><li><strong>Drive the webhook pipeline</strong> — <code>webhook.received</code> events from generic webhooks, Jira callbacks, and Manual Run are processed by the Controller to enqueue workflow executions</li></ul><h2 id="event-list" tabindex="-1">Event List <a class="header-anchor" href="#event-list" aria-label="Permalink to &quot;Event List&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Category</th><th>Event Name</th><th>Description</th></tr></thead><tbody><tr><td><strong>Agent</strong></td><td><code>agent.created</code></td><td>A new agent was created</td></tr><tr><td></td><td><code>agent.updated</code></td><td>An agent&#39;s configuration was updated</td></tr><tr><td></td><td><code>agent.deleted</code></td><td>An agent was deleted</td></tr><tr><td></td><td><code>agent.status_changed</code></td><td>An agent&#39;s status changed (e.g., active → inactive)</td></tr><tr><td><strong>Workflow</strong></td><td><code>workflow.created</code></td><td>A new workflow was created</td></tr><tr><td></td><td><code>workflow.updated</code></td><td>A workflow&#39;s configuration or steps were updated</td></tr><tr><td></td><td><code>workflow.deleted</code></td><td>A workflow was deleted</td></tr><tr><td><strong>Execution</strong></td><td><code>execution.started</code></td><td>A workflow execution started running</td></tr><tr><td></td><td><code>execution.completed</code></td><td>A workflow execution completed successfully</td></tr><tr><td></td><td><code>execution.failed</code></td><td>A workflow execution failed</td></tr><tr><td></td><td><code>execution.cancelled</code></td><td>A workflow execution was cancelled</td></tr><tr><td><strong>Step</strong></td><td><code>step.completed</code></td><td>A workflow step completed successfully</td></tr><tr><td></td><td><code>step.failed</code></td><td>A workflow step failed</td></tr><tr><td><strong>Trigger</strong></td><td><code>trigger.fired</code></td><td>A trigger fired (cron, datetime, or event match)</td></tr><tr><td><strong>Webhook</strong></td><td><code>webhook.received</code></td><td>A webhook-style trigger input was received (generic webhook, Jira callback, or Manual Run)</td></tr><tr><td><strong>User</strong></td><td><code>user.login</code></td><td>A user logged in</td></tr><tr><td></td><td><code>user.registered</code></td><td>A new user registered</td></tr><tr><td><strong>Variable</strong></td><td><code>variable.created</code></td><td>A variable was created</td></tr><tr><td></td><td><code>variable.updated</code></td><td>A variable was updated</td></tr><tr><td></td><td><code>variable.deleted</code></td><td>A variable was deleted</td></tr><tr><td><strong>Credential</strong></td><td><code>credential.access_requested</code></td><td>An agent requested access to a credential</td></tr><tr><td></td><td><code>credential.access_approved</code></td><td>A credential access request was approved</td></tr><tr><td></td><td><code>credential.access_denied</code></td><td>A credential access request was denied</td></tr></tbody></table><h2 id="event-structure" tabindex="-1">Event Structure <a class="header-anchor" href="#event-structure" aria-label="Permalink to &quot;Event Structure&quot;">​</a></h2><p>Each event record contains:</p><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>id</code></td><td>UUID</td><td>Unique event identifier</td></tr><tr><td><code>eventName</code></td><td>string</td><td>Event name (e.g., <code>agent.created</code>)</td></tr><tr><td><code>eventScope</code></td><td>enum</td><td><code>workspace</code> or <code>user</code></td></tr><tr><td><code>scopeId</code></td><td>UUID</td><td>Workspace or user ID for scoping</td></tr><tr><td><code>eventData</code></td><td>JSONB</td><td>Event-specific payload</td></tr><tr><td><code>actorId</code></td><td>UUID</td><td>User who caused the event (optional)</td></tr><tr><td><code>processedAt</code></td><td>timestamp</td><td>When the Controller processed this event (null if unprocessed)</td></tr><tr><td><code>createdAt</code></td><td>timestamp</td><td>When the event was emitted</td></tr></tbody></table><h2 id="event-triggers" tabindex="-1">Event Triggers <a class="header-anchor" href="#event-triggers" aria-label="Permalink to &quot;Event Triggers&quot;">​</a></h2><p>Event-type triggers match events by name and optional <strong>data conditions</strong> — key-value pairs that must match fields in <code>eventData</code>:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;triggerType&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;event&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;configuration&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;eventName&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;agent.status_changed&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;conditions&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">      &quot;newStatus&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;active&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>This trigger fires only when an agent&#39;s status changes to <code>active</code>.</p><h2 id="pipeline-events" tabindex="-1">Pipeline Events <a class="header-anchor" href="#pipeline-events" aria-label="Permalink to &quot;Pipeline Events&quot;">​</a></h2><p>The <code>webhook.received</code> event is special — it drives the webhook execution pipeline:</p><ol><li><strong>External webhook</strong> → <code>POST /api/webhooks/:registrationId</code> → inserts <code>webhook.received</code> event</li><li><strong>Jira callback</strong> → <code>POST /api/jira-webhooks/:triggerId?token=...</code> → inserts <code>webhook.received</code> event with <code>triggerType: &quot;jira_changes_notification&quot;</code></li><li><strong>Manual Run</strong> → <code>POST /api/workflows/:id/run</code> → inserts <code>webhook.received</code> event</li><li><strong>Controller</strong> → polls <code>system_events</code> → processes <code>webhook.received</code> → enqueues workflow execution</li></ol><p><code>webhook.received.eventData</code> commonly includes <code>triggerId</code>, <code>workflowId</code>, <code>triggerType</code>, <code>source</code>, <code>authMethod</code>, <code>eventId</code>, <code>payload</code>, <code>inputs</code>, and <code>receivedAt</code>.</p><p>Jira polling is different: <code>jira_polling</code> triggers do not emit <code>webhook.received</code>; the controller polls Jira directly and enqueues executions with <code>triggerMetadata.type = &quot;jira_polling&quot;</code>.</p><p>Generic webhooks, Jira callbacks, and Manual Run all flow through the same event pipeline, ensuring consistent processing and auditability.</p>`,18)])])}const u=t(a,[["render",r]]);export{g as __pageData,u as default};
